{
  "executive_summary": "A real-time courier bidding system built around three core mechanisms: (1) WebSocket fan-out for sub-second job broadcast to eligible couriers, (2) Redis atomic compare-and-swap for race-free single-winner acceptance, and (3) a delayed-execution fallback that auto-assigns to the highest-rated courier when the 15-second window expires with no taker. The scale target (500 concurrent bid windows × 30 couriers/zone ≈ 15,000 peak connections) is well within single-cluster capacity for both WebSocket and Redis, so the design avoids distributed coordination complexity in favor of a simple, auditable, operationally transparent architecture.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingestion Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, enriches with zone/eligibility data, and publishes an OrderPlaced domain event. Stateless, horizontally scalable.",
        "boundaries": "Owns order validation and initial persistence. Does NOT decide courier eligibility — delegates that to the Eligibility Resolver."
      },
      {
        "name": "Eligibility Resolver",
        "responsibility": "Given an order's pickup zone, determines the set of eligible couriers (online, in-zone, not currently on a job, not in cooldown). Reads from the Courier Availability projection.",
        "boundaries": "Read-only view of courier state. Does not mutate courier records. Produces an EligibleCourierSet that is passed to the Bid Window Manager."
      },
      {
        "name": "Bid Window Manager",
        "responsibility": "The core orchestrator. Creates a BidWindow aggregate in Redis for each order, fans out the job offer via WebSocket, processes acceptance bids atomically, and schedules the 15-second fallback timer. Owns the entire lifecycle of a bid window: OPEN → ACCEPTED | EXPIRED.",
        "boundaries": "Owns bid window state exclusively. No other component may write to bid window keys. Publishes BidAccepted or BidExpired domain events."
      },
      {
        "name": "WebSocket Gateway",
        "responsibility": "Maintains persistent connections with courier mobile apps. Routes job offers from the Bid Window Manager to specific courier connections. Receives acceptance messages from couriers and forwards them to the Bid Window Manager.",
        "boundaries": "Transport layer only — no business logic. Authenticates connections, manages heartbeats, tracks connection-to-courier mapping. Does NOT evaluate bids."
      },
      {
        "name": "Timeout Scheduler",
        "responsibility": "Schedules a delayed task (15 seconds) for each bid window. When fired, checks if the window is still OPEN, and if so, triggers fallback assignment to the highest-rated available courier.",
        "boundaries": "Idempotent — if the window was already accepted, the timeout is a no-op. Uses Redis keyspace notifications or a sorted-set-based delay queue."
      },
      {
        "name": "Assignment Service",
        "responsibility": "Finalizes the courier-to-order assignment after either an acceptance or a timeout fallback. Updates order state, notifies the winning courier, notifies losing couriers that the window is closed, and publishes CourierAssigned event.",
        "boundaries": "Downstream of the Bid Window Manager. Does not participate in bid arbitration."
      },
      {
        "name": "Courier Availability Projection",
        "responsibility": "Maintains a real-time view of each courier's availability status (online/offline, current job, zone, rating). Fed by courier location pings, job completion events, and shift start/end events.",
        "boundaries": "Eventually consistent read model. Acceptable staleness: < 2 seconds. Stored in Redis for fast lookups."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingestion Service",
        "to": "Eligibility Resolver",
        "contract": "resolveEligible(orderId, pickupZone) → EligibleCourierSet {courierIds[], ratings{}}",
        "coupling_type": "synchronous — in-process or internal RPC; latency budget 50ms"
      },
      {
        "from": "Order Ingestion Service",
        "to": "Bid Window Manager",
        "contract": "openBidWindow(orderId, eligibleCouriers, timeoutMs=15000) → BidWindowId",
        "coupling_type": "synchronous — the order flow blocks until the window is opened and broadcast is initiated"
      },
      {
        "from": "Bid Window Manager",
        "to": "WebSocket Gateway",
        "contract": "broadcastJobOffer(courierIds[], jobOffer{orderId, pickup, dropoff, estimatedPay, deadlineUtc})",
        "coupling_type": "asynchronous fire-and-forget via internal pub/sub channel"
      },
      {
        "from": "WebSocket Gateway",
        "to": "Bid Window Manager",
        "contract": "submitAcceptance(orderId, courierId, timestamp) → AcceptResult {won: boolean}",
        "coupling_type": "synchronous — courier needs immediate feedback on whether they won"
      },
      {
        "from": "Bid Window Manager",
        "to": "Assignment Service",
        "contract": "BidAccepted | BidExpired domain event via message bus",
        "coupling_type": "asynchronous — event-driven, decoupled"
      },
      {
        "from": "Timeout Scheduler",
        "to": "Bid Window Manager",
        "contract": "expireBidWindow(orderId) → idempotent check-and-assign",
        "coupling_type": "asynchronous — timer callback"
      },
      {
        "from": "Assignment Service",
        "to": "WebSocket Gateway",
        "contract": "notifyCouriers(courierIds[], notification{type: ASSIGNED|WINDOW_CLOSED})",
        "coupling_type": "asynchronous fire-and-forget"
      }
    ],
    "data_flow": "1) Order placed → Order Ingestion validates and calls Eligibility Resolver to get eligible couriers. 2) Ingestion calls Bid Window Manager to open a window — this writes a Redis key `bid:{orderId}` with state OPEN and schedules a 15s timeout. 3) Bid Window Manager publishes job offer through WebSocket Gateway to all eligible couriers simultaneously. 4) Couriers see the offer on mobile, tap accept → WebSocket Gateway forwards to Bid Window Manager. 5) Bid Window Manager executes `SETNX bid:{orderId}:winner {courierId}` — first writer wins, all others get 'already taken'. 6) On success, Bid Window Manager marks window ACCEPTED, publishes BidAccepted event. 7) Assignment Service consumes event, finalizes assignment, notifies all couriers. 8) If no acceptance within 15s, Timeout Scheduler fires, Bid Window Manager selects highest-rated from eligible set, force-assigns, publishes BidExpired event with fallback assignment.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Swap via Redis SETNX",
        "rationale": "The core invariant — exactly one courier wins — maps perfectly to Redis SETNX (SET if Not eXists). Single-threaded Redis guarantees atomicity without distributed locks, transactions, or consensus protocols. At 500 concurrent windows, Redis handles this trivially (100K+ ops/sec). This is simpler, faster, and more reliable than database-level optimistic locking or distributed mutexes."
      },
      {
        "pattern": "Fan-out via WebSocket with Pub/Sub Backplane",
        "rationale": "Couriers need sub-second delivery of job offers. WebSocket provides persistent bidirectional channels. A Redis Pub/Sub or channel-per-zone backplane allows multiple WebSocket Gateway instances to fan out without knowing each other — horizontal scaling without shared state."
      },
      {
        "pattern": "Sorted Set Delay Queue for Timeouts",
        "rationale": "Each bid window schedules a 15-second timeout by adding to a Redis sorted set with score = deadline_timestamp. A poller checks for expired entries every 500ms. This avoids reliance on external schedulers, survives process restarts (state is in Redis), and handles clock drift gracefully. Alternative: Redis keyspace notifications — but sorted sets give better operational visibility."
      },
      {
        "pattern": "CQRS for Courier Availability",
        "rationale": "Courier availability is a high-read, moderate-write workload (location pings every 10s from 30 couriers/zone × N zones). A dedicated read projection in Redis (hash per courier, geo-indexed) avoids contention on the write model and gives sub-millisecond eligibility lookups."
      },
      {
        "pattern": "Domain Events for Post-Assignment Workflow",
        "rationale": "After bid resolution, multiple downstream concerns (courier notification, order state update, analytics, ETA calculation) must react. Domain events decouple the Bid Window Manager from all downstream consumers, keeping the hot path (bid acceptance) fast and the system extensible."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding",
        "classification": "core",
        "aggregates": [
          {
            "name": "BidWindow",
            "root_entity": "BidWindow",
            "invariants": [
              "A BidWindow can only transition OPEN → ACCEPTED or OPEN → EXPIRED, never backwards",
              "Exactly one courier can be the winner — enforced by atomic SETNX",
              "A BidWindow must have a non-empty eligible courier set at creation",
              "The timeout deadline is immutable once set"
            ],
            "value_objects": ["JobOffer", "BidDeadline", "AcceptanceResult"],
            "domain_events": ["BidWindowOpened", "BidAccepted", "BidExpired", "BidWindowClosed"]
          }
        ]
      },
      {
        "name": "Courier Availability",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "CourierStatus",
            "root_entity": "CourierStatus",
            "invariants": [
              "A courier can only be in one zone at a time",
              "A courier on an active job is ineligible for new bids",
              "Availability requires an active shift"
            ],
            "value_objects": ["Zone", "GeoLocation", "ShiftWindow", "CourierRating"],
            "domain_events": ["CourierWentOnline", "CourierWentOffline", "CourierZoneChanged", "CourierJobCompleted"]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root_entity": "Order",
            "invariants": [
              "An order in BIDDING state must have exactly one active BidWindow",
              "An order transitions PLACED → BIDDING → ASSIGNED atomically from this context's perspective"
            ],
            "value_objects": ["PickupLocation", "DropoffLocation", "OrderValue"],
            "domain_events": ["OrderPlaced", "OrderAssigned"]
          }
        ]
      },
      {
        "name": "Assignment",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Assignment",
            "root_entity": "Assignment",
            "invariants": [
              "An assignment links exactly one order to exactly one courier",
              "A courier cannot have two simultaneous active assignments"
            ],
            "value_objects": ["AssignmentType (ACCEPTED | FALLBACK)"],
            "domain_events": ["CourierAssigned", "AssignmentConfirmed"]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier — Order Management triggers bid windows; Bidding context consumes order data but does not modify orders directly"
      },
      {
        "upstream": "Courier Availability",
        "downstream": "Bidding",
        "relationship": "Conformist — Bidding reads the availability projection as-is; it conforms to whatever schema Courier Availability publishes"
      },
      {
        "upstream": "Bidding",
        "downstream": "Assignment",
        "relationship": "Customer-Supplier — Bidding publishes resolution events; Assignment consumes them to finalize the courier-order link"
      },
      {
        "upstream": "Assignment",
        "downstream": "Order Management",
        "relationship": "Customer-Supplier — Assignment publishes CourierAssigned; Order Management updates order state"
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Redis SETNX for atomic acceptance instead of database-level optimistic concurrency",
      "gains": "Sub-millisecond atomic operations, zero lock contention, trivially handles 500+ concurrent windows, operationally simple (single Redis instance sufficient at this scale)",
      "sacrifices": "Redis is not durable by default — if Redis crashes mid-window, active bid windows are lost. Requires Redis persistence (AOF) or acceptance of rare window loss during failover.",
      "alternatives_considered": [
        "PostgreSQL SELECT FOR UPDATE — adds 5-15ms latency per acceptance attempt, creates lock contention under burst",
        "Distributed lock (Redlock) — over-engineered for this scale; single Redis master is sufficient",
        "Application-level mutex — doesn't scale horizontally"
      ]
    },
    {
      "decision": "WebSocket over Server-Sent Events or polling",
      "gains": "Bidirectional: couriers both receive offers and send acceptances over the same connection. Lower latency than HTTP polling. Natural fit for mobile apps.",
      "sacrifices": "More complex connection management, requires sticky sessions or pub/sub backplane for multi-instance deployment, mobile network transitions (WiFi→cellular) cause reconnections.",
      "alternatives_considered": [
        "SSE + HTTP POST — simpler server-side but two connection types to manage on mobile",
        "Long polling — higher latency, more HTTP overhead, doesn't scale as well for real-time",
        "Push notifications (FCM/APNs) — too slow (100-500ms+), unreliable for time-critical 15s windows"
      ]
    },
    {
      "decision": "Sorted-set delay queue for timeouts instead of external scheduler (e.g., SQS delay, cron)",
      "gains": "Sub-second precision, state co-located with bid window data in Redis, survives app restarts, simple to monitor (ZRANGEBYSCORE shows all pending timeouts).",
      "sacrifices": "Requires a dedicated poller process (adds operational surface). Poller must be singleton or use leader election to avoid duplicate firings.",
      "alternatives_considered": [
        "setTimeout in application — lost on process restart",
        "SQS delay queues — minimum 1s granularity, adds AWS dependency",
        "Database scheduled jobs — higher latency, more complex"
      ]
    },
    {
      "decision": "Single Redis instance (with replica) over Redis Cluster",
      "gains": "Simpler operations, no cross-slot issues, atomic operations just work. At 500 windows × 30 couriers = 15K keys max, a single instance is dramatically underutilized.",
      "sacrifices": "Single point of failure mitigated by replica with automatic failover (Sentinel). During failover (~5s), active bid windows may be lost — acceptable given the 15s window means at most a few orders need re-bidding.",
      "alternatives_considered": [
        "Redis Cluster — unnecessary complexity at this scale",
        "DynamoDB conditional writes — higher latency, more expensive, overkill"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Eligibility rules",
      "evolution_path": "Currently zone-based. Can evolve to distance-based, skill-based (fragile items), or ML-ranked courier matching by changing only the Eligibility Resolver — no downstream impact."
    },
    {
      "area": "Bid window duration",
      "evolution_path": "15 seconds is a parameter on BidWindow creation. Can be made dynamic per order (urgent = 8s, large = 20s) without architectural changes."
    },
    {
      "area": "Bidding model evolution",
      "evolution_path": "Current model is first-to-accept. Can evolve to price-bidding (couriers submit a price, lowest wins after window closes) by changing only the BidWindow aggregate's resolution logic. The fan-out, timeout, and assignment infrastructure remains identical."
    },
    {
      "area": "Scale-out WebSocket tier",
      "evolution_path": "Redis Pub/Sub backplane already decouples gateway instances. Adding more WebSocket Gateway nodes is a horizontal scaling operation with zero code changes."
    },
    {
      "area": "Fallback strategy",
      "evolution_path": "Currently assigns to highest-rated. Can evolve to nearest-courier, round-robin, or auction-based fallback by changing only the Timeout Scheduler's resolution policy."
    }
  ],

  "rigidity_points": [
    {
      "area": "Redis as the bid arbitration layer",
      "reason": "The atomic SETNX guarantee is the linchpin of correctness. Replacing Redis would require finding another system that provides single-key atomic conditional writes with sub-millisecond latency. This is intentionally rigid — the invariant 'exactly one winner' must never be compromised."
    },
    {
      "area": "WebSocket as the courier transport",
      "reason": "The 15-second real-time window makes WebSocket the only viable transport. Switching to polling or push notifications would violate latency requirements. Mobile app architecture is coupled to this choice."
    },
    {
      "area": "BidWindow state machine (OPEN → ACCEPTED | EXPIRED)",
      "reason": "This state machine is deliberately minimal and rigid. Adding intermediate states (e.g., PENDING_CONFIRMATION) would complicate the atomic acceptance invariant. Changes here cascade to every component."
    }
  ],

  "risks": [
    {
      "risk": "Redis failover during active bid windows causes in-flight windows to be lost",
      "severity": "medium",
      "mitigation": "Use Redis Sentinel with AOF persistence (fsync every second). Accept that during the ~5s failover, a small number of orders (proportional to 500 × 5/15 ≈ 167) may need re-bidding. Implement an Order Ingestion retry: if no BidAccepted/BidExpired event within 20s, re-open the bid window."
    },
    {
      "risk": "Mobile network latency causes courier acceptance to arrive after the window closes, despite the courier tapping 'accept' within 15s",
      "severity": "high",
      "mitigation": "Include a client-side countdown that accounts for measured RTT. Send acceptance with client timestamp; server applies a 1-second grace period. Display 14s on client when server has 15s remaining. Log and monitor 'late acceptance' rate to tune the buffer."
    },
    {
      "risk": "Courier spoofing or automated acceptance bots (fastest finger always wins)",
      "severity": "medium",
      "mitigation": "Rate-limit acceptances per courier. Require the mobile app to include a cryptographic challenge token in the acceptance payload (issued with the job offer). Monitor acceptance latency distribution — flag sub-100ms acceptances as suspicious."
    },
    {
      "risk": "WebSocket connection storms after mobile network blip (30 couriers/zone × many zones reconnect simultaneously)",
      "severity": "medium",
      "mitigation": "Implement exponential backoff with jitter on the mobile client reconnect logic. WebSocket Gateway should have connection rate limiting. Use a connection queue that drains at a controlled rate."
    },
    {
      "risk": "Stale courier availability data causes jobs to be broadcast to unavailable couriers",
      "severity": "low",
      "mitigation": "Courier Availability projection has < 2s staleness. The acceptance flow itself is the final gate — if a courier who just went offline somehow accepts, the Assignment Service can verify current status before finalizing. Belt-and-suspenders."
    },
    {
      "risk": "Timeout poller becomes a single point of failure — if it crashes, no windows expire",
      "severity": "high",
      "mitigation": "Run two poller instances using Redis-based leader election (SET with TTL). Standby takes over within 2 seconds if leader's heartbeat expires. Additionally, the Order Ingestion 20s safety-net retry catches any windows that truly fail to resolve."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three vertical slices. Slice 1 (Core): BidWindow aggregate in Redis (SETNX acceptance, sorted-set timeout queue, state machine), plus a simple HTTP endpoint simulating courier acceptance — validates the atomic invariant end-to-end without WebSocket complexity. Slice 2 (Real-time): WebSocket Gateway with Redis Pub/Sub backplane, mobile-facing job offer broadcast, and bidirectional acceptance flow. Slice 3 (Resilience): Timeout poller leader election, Order Ingestion retry safety net, late-acceptance grace period, and monitoring dashboards. Use a single Redis instance with Sentinel for HA. Language recommendation: Go or Node.js for the WebSocket Gateway (excellent async I/O), any backend language for the Bid Window Manager since Redis does the heavy lifting.",
    "files_to_create_or_modify": [
      "src/bidding/domain/BidWindow.ts — BidWindow aggregate with state machine, OPEN/ACCEPTED/EXPIRED transitions",
      "src/bidding/infrastructure/RedisBidRepository.ts — Redis SETNX-based acceptance, sorted set timeout queue, bid window CRUD",
      "src/bidding/application/BidWindowService.ts — Orchestrates window creation, acceptance processing, timeout handling",
      "src/gateway/WebSocketGateway.ts — Connection management, auth, heartbeat, courier-to-connection mapping",
      "src/gateway/PubSubBackplane.ts — Redis Pub/Sub for multi-instance fan-out of job offers",
      "src/eligibility/EligibilityResolver.ts — Zone-based eligible courier lookup from Redis geo/hash",
      "src/availability/CourierAvailabilityProjection.ts — Event-driven read model of courier status",
      "src/assignment/AssignmentService.ts — Consumes BidAccepted/BidExpired, finalizes assignment, notifies couriers",
      "src/timeout/TimeoutPoller.ts — Sorted set poller with leader election, fires expireBidWindow",
      "src/shared/events/DomainEvents.ts — Event definitions: BidWindowOpened, BidAccepted, BidExpired, CourierAssigned",
      "infrastructure/redis/schema.md — Redis key naming conventions and data structure documentation",
      "tests/bidding/BidWindow.acceptance.test.ts — Concurrent acceptance race condition tests",
      "tests/bidding/BidWindow.timeout.test.ts — Timeout fallback and idempotency tests"
    ],
    "patterns_to_follow": "Hexagonal architecture within each service: domain core has zero infrastructure dependencies, ports define interfaces (BidRepository, CourierGateway, EventPublisher), adapters implement them (RedisBidRepository, WebSocketCourierGateway, RedisEventPublisher). BidWindow aggregate encapsulates all state transitions — no external component directly mutates bid state. All Redis operations use Lua scripts where multi-step atomicity is needed (e.g., check window state + set winner + update state in one round trip).",
    "pitfalls_to_avoid": [
      "DO NOT use application-level locks for acceptance arbitration — Redis SETNX is the single source of truth for who won",
      "DO NOT store bid window state in both Redis and a database — Redis is the authoritative store during the window lifecycle; persist to database only after resolution for auditing",
      "DO NOT rely on WebSocket delivery guarantees — couriers may disconnect mid-window; the timeout fallback is the safety net, not an edge case",
      "DO NOT use Redis EXPIRE for the 15-second timeout — key expiration is best-effort and can be delayed; use a sorted set delay queue with an active poller",
      "DO NOT broadcast to couriers and open the window in separate steps — a courier could accept before the window is fully initialized; open the window in Redis FIRST, then broadcast",
      "DO NOT make the timeout poller stateless — it must handle the case where it was down for a few seconds and multiple windows expired; process all overdue windows on each tick"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 90,
    "high_confidence_areas": [
      "Redis SETNX for atomic acceptance — this is a textbook fit for the single-winner invariant",
      "WebSocket for real-time courier communication — the 15-second window rules out all other transports",
      "Sorted-set delay queue for timeouts — proven pattern, operationally transparent",
      "Scale assessment — 500 windows × 30 couriers is comfortably within single-Redis, single-cluster capacity"
    ],
    "low_confidence_areas": [
      "Exact mobile network latency distribution — the 1-second grace period is a starting guess that needs production tuning",
      "Courier behavior patterns — if couriers frequently let windows expire, the fallback path becomes the hot path and may need optimization",
      "Redis Sentinel failover impact — the 167-order estimate during failover is theoretical; real impact depends on failover duration and bid window distribution"
    ],
    "assumptions": [
      "The 500 concurrent bid windows figure represents peak load, not sustained average",
      "Couriers maintain relatively stable WebSocket connections (mobile app is foregrounded during active shifts)",
      "Zone boundaries are predefined and relatively static — not dynamically computed",
      "The marketplace has an existing order management system that will publish OrderPlaced events",
      "Redis AOF persistence with Sentinel HA is acceptable infrastructure — no requirement for multi-region"
    ]
  }
}

